evaluators.evaluation_logic:
const checkpoints = [];

// Load instrumentation event
let event = null;
try {
  const raw = localStorage.getItem('task1_quickstartCopyEvent');
  event = raw ? JSON.parse(raw) : null;
} catch (e) {
  event = null;
}

const docPages = JSON.parse(localStorage.getItem('doc_pages') || '[]');
const codeSnippets = JSON.parse(localStorage.getItem('code_snippets') || '[]');

// Identify the Quickstart: Text classification page
const quickstartPage = docPages.find(p => {
  const name = (p.name || '').toLowerCase();
  return name.includes('quickstart') && name.includes('text classification');
});

const snippet = event ? codeSnippets.find(s => s.id === event.codeSnippetId) : null;

// CP1 (0.4): User copied a Python quickstart evaluation snippet on the Text Classification quickstart page
const usedCorrectSnippet = !!(
  event &&
  quickstartPage &&
  snippet &&
  snippet.docPageId === quickstartPage.id &&
  snippet.language === 'python' &&
  snippet.snippetType === 'quickstart_evaluation'
);
checkpoints.push({ passed: usedCorrectSnippet, weight: 0.4 });

// CP2 (0.3): Config metrics are exactly ['accuracy', 'f1']
const metrics = Array.isArray(event && event.metrics) ? event.metrics : [];
const hasAccuracyF1 = metrics.length === 2 && metrics.includes('accuracy') && metrics.includes('f1');
checkpoints.push({ passed: usedCorrectSnippet && hasAccuracyF1, weight: 0.3 });

// CP3 (0.3): max_samples is 200 and model is a mini variant (e.g., contains 'mini')
const maxOk = !!(event && event.maxSamples === 200);
const modelOk = !!(event && typeof event.modelId === 'string' && event.modelId.toLowerCase().includes('mini'));
checkpoints.push({ passed: usedCorrectSnippet && maxOk && modelOk, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let event = null;
try {
  const raw = localStorage.getItem('task2_batchCurlCopyEvent');
  event = raw ? JSON.parse(raw) : null;
} catch (e) {
  event = null;
}

const endpoints = JSON.parse(localStorage.getItem('api_endpoints') || '[]');
const examples = JSON.parse(localStorage.getItem('api_examples') || '[]');

const endpoint = event ? endpoints.find(e => e.id === event.apiEndpointId) : null;
const example = event ? examples.find(ex => ex.id === event.apiExampleId) : null;

// CP1 (0.5): User copied a curl request example for the Evaluations batch creation endpoint
const isBatchCreateEndpoint = !!(
  endpoint &&
  endpoint.groupId === 'evaluations' &&
  typeof endpoint.pathTemplate === 'string' &&
  endpoint.pathTemplate.indexOf('/evaluations:batch') !== -1 &&
  endpoint.httpMethod === 'post'
);
const usedCorrectExample = !!(event && example && isBatchCreateEndpoint && example.language === 'curl' && example.exampleType === 'request');
checkpoints.push({ passed: usedCorrectExample, weight: 0.5 });

// CP2 (0.5): URL was configured with project proj_123, limit=50, cursor='cursor_abc'
const paramsOk = !!(
  usedCorrectExample &&
  event.extractedProjectId === 'proj_123' &&
  event.extractedLimit === 50 &&
  event.extractedCursor === 'cursor_abc'
);
checkpoints.push({ passed: paramsOk, weight: 0.5 });

return checkpts => checkpts.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let event = null;
try {
  const raw = localStorage.getItem('task3_costMetricJsonCopyEvent');
  event = raw ? JSON.parse(raw) : null;
} catch (e) {
  event = null;
}

const metrics = JSON.parse(localStorage.getItem('metrics') || '[]');
const metric = event ? metrics.find(m => m.id === event.metricId) : null;

// CP1 (0.4): User copied a JSON config snippet associated with a token-billing-related metric
const isTokenBillingMetric = !!(metric && metric.isTokenBillingRelated);
const usedCostMetricConfig = !!(event && isTokenBillingMetric);
checkpoints.push({ passed: usedCostMetricConfig, weight: 0.4 });

// Static default from site data: 0.0015
const defaultPrice = 0.0015;

// CP2 (0.6): price_per_1k_tokens increased above default, currency and unit unchanged (USD/tokens)
const priceOk = !!(event && typeof event.price_per_1k_tokens === 'number' && event.price_per_1k_tokens > defaultPrice);
const currencyOk = !!(event && event.currency === 'USD');
const unitOk = !!(event && event.unit === 'tokens');
checkpoints.push({ passed: usedCostMetricConfig && priceOk && currencyOk && unitOk, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const states = JSON.parse(localStorage.getItem('config_builder_states') || '[]');
const variants = JSON.parse(localStorage.getItem('model_variants') || '[]');
const snippets = JSON.parse(localStorage.getItem('code_snippets') || '[]');

const state = states.length > 0 ? states[0] : null;

// CP1 (0.4): Builder state is for text_generation with max_samples=50 and metrics exactly ['accuracy','latency']
let settingsOk = false;
if (state) {
  const metricsSel = Array.isArray(state.selectedMetricIds) ? state.selectedMetricIds : [];
  const hasAccLat = metricsSel.length === 2 && metricsSel.includes('accuracy') && metricsSel.includes('latency');
  settingsOk = (state.taskType === 'text_generation' && state.maxSamples === 50 && hasAccLat);
}
checkpoints.push({ passed: settingsOk, weight: 0.4 });

// CP2 (0.3): Variants include >=2 candidates and >=1 baseline, all with distinct modelIds; candidates have different nonzero temps, baseline has temp 0.0
let variantsOk = false;
if (state) {
  const stateVariants = variants.filter(v => v.configBuilderStateId === state.id);
  const candidateVariants = stateVariants.filter(v => v.role === 'candidate');
  const baselineVariants = stateVariants.filter(v => v.role === 'baseline');
  if (candidateVariants.length >= 2 && baselineVariants.length >= 1) {
    const modelIds = stateVariants.map(v => v.modelId);
    const distinctModelIds = new Set(modelIds).size === modelIds.length;
    const candTemps = candidateVariants.map(v => v.temperature).filter(t => typeof t === 'number');
    const baselineTemps = baselineVariants.map(v => v.temperature).filter(t => typeof t === 'number');
    const candTempsValid = candTemps.length >= 2 && candTemps[0] > 0 && candTemps[1] > 0 && candTemps[0] !== candTemps[1];
    const baselineTempOk = baselineTemps.some(t => t === 0);
    variantsOk = distinctModelIds && candTempsValid && baselineTempOk;
  }
}
checkpoints.push({ passed: settingsOk && variantsOk, weight: 0.3 });

// CP3 (0.3): A config was generated from the builder (generatedConfigSnippetId set and snippet exists as config_builder_output)
let generatedOk = false;
if (state && state.generatedConfigSnippetId) {
  const snippet = snippets.find(s => s.id === state.generatedConfigSnippetId);
  generatedOk = !!(snippet && snippet.snippetType === 'config_builder_output' && snippet.language === 'json');
}
checkpoints.push({ passed: settingsOk && variantsOk && generatedOk, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let event = null;
try {
  const raw = localStorage.getItem('task5_runBatchEvalCopyEvent');
  event = raw ? JSON.parse(raw) : null;
} catch (e) {
  event = null;
}

const codeSnippets = JSON.parse(localStorage.getItem('code_snippets') || '[]');
const snippet = event ? codeSnippets.find(s => s.id === event.codeSnippetId) : null;

// CP1 (0.4): User copied a JavaScript snippet that uses runBatchEvaluation
const isRunBatchSnippet = !!(
  snippet &&
  snippet.language === 'javascript' &&
  typeof snippet.code === 'string' &&
  snippet.code.includes('runBatchEvaluation')
);
checkpoints.push({ passed: event && isRunBatchSnippet, weight: 0.4 });

// CP2 (0.6): Concurrency was set to 10 in the copied snippet
const concurrencyOk = !!(event && isRunBatchSnippet && event.concurrency === 10);
checkpoints.push({ passed: concurrencyOk, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let event = null;
try {
  const raw = localStorage.getItem('task6_bleuExampleEndpointCopyEvent');
  event = raw ? JSON.parse(raw) : null;
} catch (e) {
  event = null;
}

const examples = JSON.parse(localStorage.getItem('evaluation_examples') || '[]');
const metrics = JSON.parse(localStorage.getItem('metrics') || '[]');

const filterState = event && event.filterStateAtCopy ? event.filterStateAtCopy : {};
const selectedMetricId = filterState.selectedMetricId || null;
const minDatasetSize = filterState.minDatasetSize;

const metric = selectedMetricId ? metrics.find(m => m.id === selectedMetricId) : null;

// CP1 (0.4): Filter at copy time targeted BLEU with min dataset size >= 1000
const filterCorrect = !!(
  event &&
  metric &&
  metric.id === 'bleu' &&
  typeof minDatasetSize === 'number' &&
  minDatasetSize >= 1000
);
checkpoints.push({ passed: filterCorrect, weight: 0.4 });

// Recompute filtered examples using the filter state at copy time
const filteredExamples = examples.filter(ex => {
  if (!Array.isArray(ex.metricIds)) return false;
  if (selectedMetricId && !ex.metricIds.includes(selectedMetricId)) return false;
  if (typeof minDatasetSize === 'number') {
    if (typeof ex.datasetSize !== 'number' || ex.datasetSize < minDatasetSize) return false;
  }
  return true;
});

const example = event ? examples.find(ex => ex.id === event.evaluationExampleId) : null;

// CP2 (0.3): The copied example itself matches the BLEU + min-size filter
const exampleQualifies = !!(
  filterCorrect &&
  example &&
  Array.isArray(example.metricIds) &&
  example.metricIds.includes(selectedMetricId) &&
  typeof example.datasetSize === 'number' &&
  example.datasetSize >= minDatasetSize
);
checkpoints.push({ passed: exampleQualifies, weight: 0.3 });

// CP3 (0.3): The example is the 3rd in the filtered list and the copied endpointPath matches the example's endpointPath
let indexOk = false;
let pathOk = false;
if (exampleQualifies) {
  const idx = filteredExamples.findIndex(ex => ex.id === example.id);
  indexOk = (idx === 2); // 0-based index 2 => 3rd example
  pathOk = !!(event && event.endpointPath === example.endpointPath);
}
checkpoints.push({ passed: exampleQualifies && indexOk && pathOk, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let event = null;
try {
  const raw = localStorage.getItem('task7_datasetCreateCurlV2CopyEvent');
  event = raw ? JSON.parse(raw) : null;
} catch (e) {
  event = null;
}

const endpoints = JSON.parse(localStorage.getItem('api_endpoints') || '[]');
const siteSettingsArr = JSON.parse(localStorage.getItem('site_settings') || '[]');
const site = siteSettingsArr[0] || null;

const endpoint = event ? endpoints.find(e => e.id === event.apiEndpointId) : null;

const docsVersionSwitched = !!(site && site.currentDocsVersionId === 'v2');

const endpointIsV2DatasetCreate = !!(
  endpoint &&
  endpoint.groupId === 'datasets' &&
  endpoint.apiVersion === 'v2' &&
  endpoint.httpMethod === 'post' &&
  typeof endpoint.pathTemplate === 'string' &&
  endpoint.pathTemplate.indexOf('/v2/projects/') === 0 &&
  endpoint.pathTemplate.includes('/datasets')
);

// CP1 (0.4): Docs version is v2 and the copied example is for the v2 datasets create endpoint
const baseOk = !!(event && docsVersionSwitched && endpointIsV2DatasetCreate && event.apiVersion === 'v2');
checkpoints.push({ passed: baseOk, weight: 0.4 });

// CP2 (0.3): Path template exactly matches /v2/projects/{project_id}/datasets
const pathTemplateOk = !!(baseOk && endpoint.pathTemplate === '/v2/projects/{project_id}/datasets' && event.pathTemplate === endpoint.pathTemplate);
checkpoints.push({ passed: pathTemplateOk, weight: 0.3 });

// CP3 (0.3): Copied curl code uses the v2 base URL with /v2/projects/ in the path
const codeHasV2 = !!(event && typeof event.code === 'string' && event.code.includes('https://api.aievaldocs.com/v2/projects/'));
checkpoints.push({ passed: baseOk && codeHasV2, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const runs = JSON.parse(localStorage.getItem('playground_evaluation_runs') || '[]');

// Find runs that match the required configuration
const qualifyingRuns = runs.filter(run => {
  if (!run) return false;
  if (run.taskType !== 'text_classification') return false;
  if (run.sampleSize !== 10) return false;
  if (!Array.isArray(run.metricIds)) return false;
  if (!run.metricIds.includes('accuracy') || !run.metricIds.includes('latency')) return false;
  if (typeof run.accuracyWeight !== 'number' || typeof run.latencyWeight !== 'number') return false;
  if (!(run.accuracyWeight > run.latencyWeight)) return false;
  if (run.status !== 'running') return false; // indicates the evaluation was started
  return true;
});

// CP1 (0.7): At least one Playground run matches task type, sample size, metrics, and weighting
checkpoints.push({ passed: qualifyingRuns.length > 0, weight: 0.7 });

// CP2 (0.3): Among qualifying runs, at least one has a reasonably short test name
const shortNameRuns = qualifyingRuns.filter(run => typeof run.evaluationName === 'string' && run.evaluationName.length <= 32);
checkpoints.push({ passed: shortNameRuns.length > 0, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
